#!/usr/bin/env bash
# team-event-log.sh — WARN-ONLY observability hook for agent-team events
# (generated by scaffold-generate; placeholder-free). Wired in .claude/settings.json
# under TeammateIdle + TaskCompleted.
#
# It appends a durable, lead-readable event line to ~/.claude/team-events/<label>.jsonl
# so the lead can reconstruct an idle/completion timeline beyond the harness's ephemeral
# idle-notifications — and spot the documented drift "a teammate idled but never marked
# its in-progress task completed" (scan: a TeammateIdle with no following TaskCompleted
# for that teammate's task).
#
# DELIBERATELY WARN-ONLY — it ALWAYS exits 0 and NEVER emits {"continue": false}.
# An exit-2 TeammateIdle ("keep working") would break two designed flows:
#   - the /tdd Step-2.5 / Step-9 idle-for-review pattern (the implementer idles WAITING
#     for the orchestrator's APPROVED. / commit-message reply — that idle is correct), and
#   - slice atomicity (the current slice always finishes; nothing keeps a teammate working
#     past a clean break).
# So this hook observes; it never enforces. Enforcement lives at the checkpoints + gates.
#
# No-op for any session without one of OUR team-registry entries (solo / bootstrap /
# generation sessions are never logged), so it's silent outside team mode.

set -euo pipefail
command -v jq >/dev/null 2>&1 || exit 0   # never fail the harness on a missing dep

payload=$(cat 2>/dev/null || true)
get() { printf '%s' "$payload" | jq -r "$1 // empty" 2>/dev/null || true; }

event=$(get '.hook_event_name')
sid=$(get '.session_id'); [ -n "$sid" ] || sid="${CLAUDE_CODE_SESSION_ID:-}"
[ -n "$sid" ] || exit 0

# Our monitoring label comes from OUR registry (keyed by session_id), NOT the payload's
# deprecated team_name. No registry entry => not a monitored team session => no-op.
reg="$HOME/.claude/team-registry/${sid}.json"
[ -f "$reg" ] || exit 0
label=$(jq -r '.team // empty' "$reg" 2>/dev/null || true)
[ -n "$label" ] || exit 0
name=$(jq -r '.name // empty' "$reg" 2>/dev/null || true)
[ -n "$name" ] || name=$(get '.teammate_name')

dir="$HOME/.claude/team-events"; mkdir -p "$dir"
ts=$(date -u +%Y-%m-%dT%H:%M:%SZ 2>/dev/null || echo unknown)

jq -nc \
  --arg ts "$ts" --arg event "${event:-unknown}" --arg session "$sid" \
  --arg name "$name" --arg task "$(get '.task_id')" --arg subject "$(get '.task_subject')" \
  '{ts:$ts, event:$event, session:$session, name:$name}
   + (if $task    != "" then {task:$task}       else {} end)
   + (if $subject != "" then {subject:$subject} else {} end)' \
  >> "$dir/${label}.jsonl" 2>/dev/null || true

exit 0
